class LUPrefix:

    def __init__(self, n: int):
        self.video = 1
        self.last_uploaded = -1
        self.uploaded = set()

    def upload(self, video: int) -> None:
        if video >= self.last_uploaded + 1:
            self.last_uploaded = video
            self.uploaded.add(video)

    def longest(self) -> int:
        return len(self.uploaded)
